tape('values, abort', function (t) {

  t.plan(3)

  var err = new Error('intentional')

  var read = pull.values([1,2,3], function (err) {
    t.end()
  })

  read(null, function (_, one) {
    t.notOk(_)
    t.equal(one, 1)
